import{_ as e,o as r,c as t,ag as o}from"./chunks/framework.ClpDZR9J.js";const p=JSON.parse('{"title":"设计模式面试题","description":"","frontmatter":{},"headers":[],"relativePath":"algorithm/design-patterns/index.md","filePath":"algorithm/design-patterns/index.md"}'),i={name:"algorithm/design-patterns/index.md"};function n(l,a,s,h,d,c){return r(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="设计模式面试题" tabindex="-1">设计模式面试题 <a class="header-anchor" href="#设计模式面试题" aria-label="Permalink to &quot;设计模式面试题&quot;">​</a></h1><p>设计模式是软件工程中常见的解决方案，掌握设计模式能够提高代码的可维护性、可扩展性和复用性。</p><h2 id="模块导航" tabindex="-1">模块导航 <a class="header-anchor" href="#模块导航" aria-label="Permalink to &quot;模块导航&quot;">​</a></h2><h3 id="_1-创建型模式" tabindex="-1">1. 创建型模式 <a class="header-anchor" href="#_1-创建型模式" aria-label="Permalink to &quot;1. 创建型模式&quot;">​</a></h3><p>单例模式、工厂模式、抽象工厂模式、建造者模式、原型模式</p><h3 id="_2-结构型模式" tabindex="-1">2. 结构型模式 <a class="header-anchor" href="#_2-结构型模式" aria-label="Permalink to &quot;2. 结构型模式&quot;">​</a></h3><p>适配器模式、装饰器模式、代理模式、外观模式、桥接模式、组合模式、享元模式</p><h3 id="_3-行为型模式" tabindex="-1">3. 行为型模式 <a class="header-anchor" href="#_3-行为型模式" aria-label="Permalink to &quot;3. 行为型模式&quot;">​</a></h3><p>观察者模式、策略模式、命令模式、责任链模式、状态模式、访问者模式、中介者模式、备忘录模式、迭代器模式、模板方法模式</p><h3 id="_4-前端设计模式" tabindex="-1">4. 前端设计模式 <a class="header-anchor" href="#_4-前端设计模式" aria-label="Permalink to &quot;4. 前端设计模式&quot;">​</a></h3><p>前端开发中常用的设计模式，如模块模式、发布订阅模式、单例模式等</p><h3 id="_5-设计原则" tabindex="-1">5. 设计原则 <a class="header-anchor" href="#_5-设计原则" aria-label="Permalink to &quot;5. 设计原则&quot;">​</a></h3><p>SOLID 原则、DRY 原则、KISS 原则、YAGNI 原则</p><h3 id="_6-反模式" tabindex="-1">6. 反模式 <a class="header-anchor" href="#_6-反模式" aria-label="Permalink to &quot;6. 反模式&quot;">​</a></h3><p>常见的反模式及其避免方法</p><h2 id="学习建议" tabindex="-1">学习建议 <a class="header-anchor" href="#学习建议" aria-label="Permalink to &quot;学习建议&quot;">​</a></h2><ol><li><strong>理解原则</strong> - 先理解设计原则，再学习设计模式</li><li><strong>分类学习</strong> - 按创建型、结构型、行为型分类学习</li><li><strong>实际应用</strong> - 在实际项目中应用设计模式</li><li><strong>代码示例</strong> - 多看代码示例，理解实现细节</li><li><strong>避免滥用</strong> - 不要为了用模式而用模式</li><li><strong>前端场景</strong> - 关注前端开发中的设计模式应用</li></ol><h2 id="参考资源" tabindex="-1">参考资源 <a class="header-anchor" href="#参考资源" aria-label="Permalink to &quot;参考资源&quot;">​</a></h2><ul><li><a href="https://book.douban.com/subject/1052241/" target="_blank" rel="noreferrer">设计模式：可复用面向对象软件的基础</a></li><li><a href="https://addyosmani.com/resources/essentialjsdesignpatterns/book/" target="_blank" rel="noreferrer">JavaScript 设计模式</a></li><li><a href="https://refactoring.guru/zh-cn/design-patterns" target="_blank" rel="noreferrer">图解设计模式</a></li><li><a href="https://design-patterns.readthedocs.io/" target="_blank" rel="noreferrer">设计模式可视化</a></li></ul>',19)])])}const u=e(i,[["render",n]]);export{p as __pageData,u as default};
